module RefModule(out, a, b, c, d, e, f, g, h, sel);parameter n = 1;

   output [n-1:0] out;
   input [n-1:0]  a, b, c, d, e, f, g, h;
   input [2:0]    sel;

   wire __sel_tmp = sel == 3'b000;
   assign out = __sel_tmp ? a : sel == 3'b001 ? b :
                        sel == 3'b010 ? c : 
                        sel == 3'b011 ? d :
                        sel == 3'b100 ? e :
                        sel == 3'b101 ? f :
                        sel == 3'b110 ? g :
                        sel == 3'b111 ? h : 0;endmodule
